import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { 
  listenAuction, startAuction, closeAuction, 
  listenPlayers, addPlayer, deletePlayer, 
  resetAllWins, clearAllRecords 
} from '../firebase/services';
import toast from 'react-hot-toast';

export default function AdminDashboard() {
  const { logout } = useAuth();
  const [auction, setAuction] = useState(null);
  const [players, setPlayers] = useState([]);
  const [settings, setSettings] = useState({ monthlyAmount: 5000, totalPlayers: 10 });
  const [newPlayer, setNewPlayer] = useState({ name: '', email: '', password: '' });
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const unsubs = [
      listenAuction(setAuction),
      listenPlayers((data) => {
        // FILTER: Keep the Admin out of the list
        const onlyFamily = data.filter(p => !p.isAdmin);
        setPlayers(onlyFamily);
      })
    ];
    return () => unsubs.forEach(u => u());
  }, []);

  const handleAddPlayer = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await addPlayer(newPlayer.email, newPlayer.password, newPlayer.name);
      toast.success("Family member added!");
      setNewPlayer({ name: '', email: '', password: '' });
    } catch (err) { toast.error(err.message); }
    finally { setLoading(false); }
  };

  const handleMaintenanceReset = async () => {
    if (!window.confirm("⚠️ RESET SYSTEM: Delete all records and reset all winners for a new cycle?")) return;
    try {
      await clearAllRecords();
      await resetAllWins();
      toast.success("System Reset!");
    } catch (err) { toast.error("Reset failed"); }
  };

  return (
    <div className="page-wide">
      <div className="navbar">
        <div className="navbar-brand">👑 Admin Dashboard</div>
        <button className="btn btn-danger btn-sm" onClick={logout}>Logout</button>
      </div>

      {/* 1. ADD PLAYER SECTION */}
      <div className="card" style={{ marginBottom: '20px' }}>
        <h3 className="card-title">Add New Family Member</h3>
        <form onSubmit={handleAddPlayer} style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr auto', gap: '10px', marginTop: '15px' }}>
          <input type="text" className="form-input" placeholder="Name" required value={newPlayer.name} onChange={e => setNewPlayer({...newPlayer, name: e.target.value})} />
          <input type="email" className="form-input" placeholder="Email" required value={newPlayer.email} onChange={e => setNewPlayer({...newPlayer, email: e.target.value})} />
          <input type="password" className="form-input" placeholder="Password" required value={newPlayer.password} onChange={e => setNewPlayer({...newPlayer, password: e.target.value})} />
          <button className="btn btn-primary" disabled={loading}>{loading ? "..." : "Add"}</button>
        </form>
      </div>

      {/* 2. AUCTION CONTROL SECTION */}
      <div className="card" style={{ textAlign: 'center', padding: '40px 20px', marginBottom: '20px', border: auction?.active ? '2px solid var(--gold)' : 'none' }}>
        {auction?.active ? (
          <div>
            <div className="badge badge-green">LIVE AUCTION</div>
            <h1 style={{ fontSize: '4rem', color: 'var(--gold)', margin: '10px 0' }}>
              ₹{auction.currentBid?.toLocaleString('en-IN')}
            </h1>
            <p style={{ fontSize: '1.2rem' }}>Leading: <b>{auction.currentBidderName || "No bids"}</b></p>
            <button className="btn btn-danger" style={{ marginTop: '20px', padding: '12px 40px' }} onClick={() => closeAuction(auction)}>
              STOP AUCTION & SAVE WINNER
            </button>
          </div>
        ) : (
          <div>
            <h3>Ready for next month?</h3>
            <div style={{ display: 'flex', justifyContent: 'center', gap: '15px', marginTop: '15px' }}>
              <div style={{ textAlign: 'left' }}>
                <label className="form-label">BC Amount</label>
                <input type="number" className="form-input" value={settings.monthlyAmount} onChange={e => setSettings({...settings, monthlyAmount: Number(e.target.value)})} />
              </div>
              <button className="btn btn-primary" style={{ alignSelf: 'flex-end', padding: '10px 30px' }} onClick={() => startAuction(settings)}>
                START AUCTION NOW
              </button>
            </div>
          </div>
        )}
      </div>

      {/* 3. PLAYER LIST SECTION */}
      <div className="card">
        <h3 className="card-title">Family Members ({players.length})</h3>
        <table className="records-table" style={{ marginTop: '15px' }}>
          <thead>
            <tr>
              <th>Name</th>
              <th>Email</th>
              <th>Status</th>
              <th>Action</th>
            </tr>
          </thead>
          <tbody>
            {players.map(p => (
              <tr key={p.id}>
                <td style={{ fontWeight: 'bold' }}>{p.name}</td>
                <td>{p.email}</td>
                <td>
                  {p.hasWon ? <span className="badge badge-green">Won ({p.wonMonth})</span> : <span className="badge badge-muted">Eligible</span>}
                </td>
                <td>
                  <button className="btn btn-danger btn-sm" onClick={() => deletePlayer(p.id, p.name)}>🗑️ Delete</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* 4. MAINTENANCE (FOOTER) */}
      <div style={{ marginTop: '40px', padding: '20px', borderTop: '1px dashed #444', textAlign: 'center' }}>
        <button className="btn btn-ghost btn-sm" style={{ color: '#ff4d4d' }} onClick={handleMaintenanceReset}>
          Reset All Records (Cycle Complete)
        </button>
      </div>
    </div>
  );
}
